module priority_encoder(
    input [3:0] in,
    output reg [1:0] invalid_out,
    output reg valid);
always @(*) begin
    if (in[3]) begin
        invalid_out = 2'b11;
        valid = 1'b1;
    end else if (in[2]) begin
        invalid_out = 2'b10;
        valid = 1'b1;
    end else if (in[1]) begin
        invalid_out = 2'b01;
        valid = 1'b1;
    end else if (in[0]) begin
        invalid_out = 2'b00;
        valid = 1'b1;
    end else begin
        invalid_out = 2'b00;
        valid = 1'b0;
    end
end
endmodule
